const chunks = [];
process.stdin.on\('data', d => chunks.push\(d\)\);
process.stdin.on\('end', \(\) => {
  const d = JSON.parse\(Buffer.concat\(chunks\)\);
  const comps = d?.events?.[0]?.competitions?.[0]?.competitors ?? [];
  comps.forEach\(c => {
    const name = c.athlete?.displayName ?? c.athlete?.shortName ?? '?';
    const status = c.status?.type?.name ?? '';
    const score = c.score?.displayValue ?? '-';
    console.log\(JSON.stringify\({ id: c.athlete?.id, name, status, score }\)\);
  }\);
}\);
" 2>&1 | head -120)

